			https://forgerock-green.preprod-gcdm.cn-north-1.aws.cloud.bmw/am/json/authenticate
			POST

				resource=2.0, protocol=1.0


				application/json


				@(((string)context.Variables["password"]) ?? "")


				@(((string)context.Variables["username"]) ?? "")


			{}


		<set-variable name="tokenId" value="@{  
        var token = "";  
        var resp = context.Variables.ContainsKey("authResp") ? (IResponse)context.Variables["authResp"] : null;  
        if (resp != null) {  
          try {  
            var jo = resp.Body.As();  
            token = (string)(jo?["tokenId"]) ?? "";  
          } catch {}  
        }  
        return token;  
      }" />






						application/json

					{"error":"invalid_credentials_or_no_token"}









				application/json


				@($"GCDMSSO={(string)context.Variables["tokenId"]}")

			@{  
        var redirectTo = (string)context.Variables["redirect_to"] ?? "";  
        var jsonSafe = redirectTo.Replace("\\", "\\\\").Replace("\"", "\\\"");  
        return "{\"redirect_to\":\"" + jsonSafe + "\"}";  
      }
